using System;\nusing System.Collections.Specialized;\nusing System.Reflection;\nusing System.Web.Profile;\nusing System.Web.UI;\nusing Mono.Data.Sqlite;\nusing TechInfoSystems.Data.SQLite;\nusing Xunit;\n\nnamespace TechInfoSystems.Data.SQLite.Tests\n{\n    public class SQLiteProfileProviderTests\n    {\n        [Fact]\n        public void DeleteProfiles_DeletesProfile_UsesAtParameterMarkerForUserId()\n        {\n            // Arrange: configure provider private connection string fields\n            var provider = new SQLiteProfileProvider();\n            SetPrivateStaticField(typeof(SQLiteProfileProvider), \"_connectionString\", \"Data Source=:memory:;Version=3;New=True;\");\n            SetPrivateStaticField(typeof(SQLiteProfileProvider), \"_membershipApplicationId\", \"app1\");\n\n            using var cn = new SqliteConnection(\"Data Source=:memory:;Version=3;New=True;\");\n            cn.Open();\n\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = @\"\nCREATE TABLE aspnet_Users (\n    UserId TEXT PRIMARY KEY,\n    Username TEXT,\n    LoweredUsername TEXT,\n    ApplicationId TEXT,\n    IsAnonymous INTEGER,\n    LastActivityDate TEXT\n);\nCREATE TABLE aspnet_Profile (\n    UserId TEXT PRIMARY KEY,\n    PropertyNames TEXT,\n    PropertyValuesString TEXT,\n    PropertyValuesBinary BLOB,\n    LastUpdatedDate TEXT\n);\";\n                cmd.ExecuteNonQuery();\n            }\n\n            // Seed one user + profile\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = \"INSERT INTO aspnet_Users(UserId, Username, LoweredUsername, ApplicationId, IsAnonymous, LastActivityDate) VALUES (@u,@un,@lun,@app,0,@dt);\";\n                cmd.Parameters.AddWithValue(\"@u\", \"u1\");\n                cmd.Parameters.AddWithValue(\"@un\", \"Bob\");\n                cmd.Parameters.AddWithValue(\"@lun\", \"bob\");\n                cmd.Parameters.AddWithValue(\"@app\", \"app1\");\n                cmd.Parameters.AddWithValue(\"@dt\", DateTime.UtcNow.ToString(\"o\"));\n                cmd.ExecuteNonQuery();\n            }\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.CommandText = \"INSERT INTO aspnet_Profile(UserId, PropertyNames, PropertyValuesString, PropertyValuesBinary, LastUpdatedDate) VALUES (@u,'','',X'00',@dt);\";\n                cmd.Parameters.AddWithValue(\"@u\", \"u1\");\n                cmd.Parameters.AddWithValue(\"@dt\", DateTime.UtcNow.ToString(\"o\"));\n                cmd.ExecuteNonQuery();\n            }\n\n            // Put connection into a transaction and into HttpContext so provider uses it\n            var httpCtx = new System.Web.HttpContext(\n                new System.Web.HttpRequest(\"\", \"http://localhost/\", \"\"),\n                new System.Web.HttpResponse(new System.IO.StringWriter()));\n            System.Web.HttpContext.Current = httpCtx;\n            var tran = cn.BeginTransaction();\n            httpCtx.Items[\"SQLiteTran\"] = tran;\n\n            // Act\n            var profiles = new ProfileInfoCollection\n            {\n                new ProfileInfo(\"Bob\", false, DateTime.UtcNow, DateTime.UtcNow, 0)\n            };\n\n            var deleted = provider.DeleteProfiles(profiles);\n\n            // Assert: deleted count and row actually removed\n            Assert.Equal(1, deleted);\n\n            using (var cmd = cn.CreateCommand())\n            {\n                cmd.Transaction = tran;\n                cmd.CommandText = \"SELECT COUNT(*) FROM aspnet_Profile WHERE UserId = @u\";\n                cmd.Parameters.AddWithValue(\"@u\", \"u1\");\n                var remaining = Convert.ToInt64(cmd.ExecuteScalar());\n                Assert.Equal(0, remaining);\n            }\n        }\n\n        private static void SetPrivateStaticField(Type t, string fieldName, object value)\n        {\n            var f = t.GetField(fieldName, BindingFlags.Static | BindingFlags.NonPublic);\n            Assert.NotNull(f);\n            f!.SetValue(null, value);\n        }\n    }\n}\n